// Parse input từ Telegram message
// Format: "Tên sách | Giá | Link affiliate"

const message = $input.item.json.message;
const text = message.caption || '';
const photo = message.photo;
const chatId = message.chat.id;

// Split input by delimiter
const parts = text.split('|').map(p => p.trim());

if (parts.length < 3) {
  throw new Error('Format không đúng! Vui lòng gửi: Tên sách | Giá | Link affiliate');
}

// Generate unique book ID
const bookId = 'BOOK_' + Date.now();

return {
  json: {
    bookId: bookId,
    bookName: parts[0],
    price: parts[1],
    affiliateLink: parts[2],
    photoFileId: photo ? photo[photo.length - 1].file_id : null,
    chatId: chatId,
    timestamp: new Date().toISOString(),
    status: 'received'
  }
};

// Extract relevant book information từ Google Books API

const apiResponse = $input.item.json;
const bookData = $('Parse Book Input').item.json;

let bookInfo = {
  title: bookData.bookName,
  description: 'Không tìm thấy mô tả',
  authors: [],
  categories: [],
  pageCount: 0,
  publishedDate: '',
  language: 'vi'
};

if (apiResponse.items && apiResponse.items.length > 0) {
  const firstResult = apiResponse.items[0].volumeInfo;

  bookInfo = {
    title: firstResult.title || bookData.bookName,
    description: firstResult.description || 'Không tìm thấy mô tả',
    authors: firstResult.authors || [],
    categories: firstResult.categories || ['General'],
    pageCount: firstResult.pageCount || 0,
    publishedDate: firstResult.publishedDate || '',
    language: firstResult.language || 'vi'
  };
}

// Merge với original data
return {
  json: {
    ...bookData,
    bookInfo: bookInfo,
    category: bookInfo.categories[0] || 'general'
  }
};

// Extract script từ Groq API response

const response = $input.item.json;
const script = response.choices[0].message.content.trim();

// Get previous data
const bookData = $('Extract Book Info').item.json;

// Add retry count
const retryCount = $input.item.json.retryCount || 0;

return {
  json: {
    ...bookData,
    generatedScript: script,
    scriptLength: script.length,
    retryCount: retryCount,
    scriptGeneratedAt: new Date().toISOString()
  }
};

// Handle rejection - increment retry count

const callbackData = $input.item.json.callback_query.data;
const bookId = callbackData.replace('reject_', '');

// Get previous script data từ workflow storage hoặc Sheet
// Simplified: Just return retry signal

const retryCount = ($input.item.json.retryCount || 0) + 1;

if (retryCount >= 3) {
  throw new Error('Đã retry 3 lần. Vui lòng kiểm tra yêu cầu.');
}

return {
  json: {
    bookId: bookId,
    action: 'regenerate',
    retryCount: retryCount
  }
};

