// Extract video URLs từ Pexels response

const response = $input.item.json;
const videos = [];

if (response.videos && response.videos.length > 0) {
  for (const video of response.videos) {
    // Get portrait HD video file
    const hdFile = video.video_files.find(f => 
      f.width === 1080 && f.height === 1920
    ) || video.video_files.find(f => 
      f.quality === 'hd'
    ) || video.video_files[0];

    videos.push({
      id: video.id,
      url: hdFile.link,
      width: hdFile.width,
      height: hdFile.height,
      duration: video.duration,
      keyword: $json.searchKeywords
    });
  }
}

return videos.map(v => ({ json: v }));

// Select background music dựa trên category

const category = $('Save Approved Script').item.json.category || 'general';

// Pre-uploaded music files trên Drive
