// NOTE: Cần upload music files trước và update Drive IDs

/**
 * VIDEO COMPOSITION với FFmpeg
 * 
 * Inputs:
 * - Videos từ Aggregate Videos node
 * - Voiceover từ Upload Voiceover node
 * - Music từ Download Music node
 * 
 * Output:
 * - Final video MP4 (1080x1920, 30fps)
 * 
 * GIẢI THÍCH:
 * Node này sẽ dùng fluent-ffmpeg để ghép video.
 * Do n8n code node có giới hạn, đây là pseudo-code.
 * Trong thực tế, bạn có thể:
 * 1. Dùng n8n Execute Command node với ffmpeg CLI
 * 2. Hoặc tạo custom node riêng
 * 3. Hoặc call external API/service
 */

const ffmpeg = require('fluent-ffmpeg');
const fs = require('fs');
const path = require('path');

// Get data từ previous nodes
const videos = $('Aggregate Videos').item.json.data; // Array of video Drive IDs
const voiceoverData = $('Upload Voiceover to Drive').item.json;
const musicData = $('Download Music from Drive').item.json;

// For simplicity, assume files đã được download về temp folder
// Trong thực tế, cần download từ Drive về first

const tempDir = '/tmp/video-composition';
if (!fs.existsSync(tempDir)) fs.mkdirSync(tempDir, { recursive: true });

// Video settings
const OUTPUT_WIDTH = 1080;
const OUTPUT_HEIGHT = 1920;
const TARGET_DURATION = 60; // seconds
const VIDEO_FPS = 30;

try {
  // Step 1: Download all videos từ Drive
  const videoFiles = [];
  for (let i = 0; i < Math.min(videos.length, 5); i++) {
    const videoPath = path.join(tempDir, `video_${i}.mp4`);
    // Download logic here (simplified)
    videoFiles.push(videoPath);
  }

  // Step 2: Create concat file for FFmpeg
  const concatFile = path.join(tempDir, 'concat.txt');
  const clipDuration = TARGET_DURATION / videoFiles.length;

  let concatContent = '';
  videoFiles.forEach(file => {
    concatContent += `file '${file}'\n`;
    concatContent += `duration ${clipDuration}\n`;
  });
  fs.writeFileSync(concatFile, concatContent);

  // Step 3: Voiceover và Music paths
  const voiceoverPath = path.join(tempDir, 'voiceover.mp3');
  const musicPath = path.join(tempDir, 'music.mp3');
  // Download logic here

  // Step 4: FFmpeg composition
  const outputPath = path.join(tempDir, 'final_video.mp4');

  await new Promise((resolve, reject) => {
    ffmpeg()
      // Video inputs từ concat file
      .input(concatFile)
      .inputOptions(['-f', 'concat', '-safe', '0'])

      // Audio inputs
      .input(voiceoverPath) // Input 1
      .input(musicPath)      // Input 2

      // Complex filter
      .complexFilter([
        // Scale video to 1080x1920
        `[0:v]scale=${OUTPUT_WIDTH}:${OUTPUT_HEIGHT}:force_original_aspect_ratio=increase,crop=${OUTPUT_WIDTH}:${OUTPUT_HEIGHT}[video]`,

        // Mix audio: voiceover 100%, music 20%
        '[1:a]volume=1.0[voice]',
        '[2:a]volume=0.2[music]',
        '[voice][music]amix=inputs=2:duration=first[audio]'
      ])

      // Output options
      .outputOptions([
        '-map', '[video]',
        '-map', '[audio]',
        '-c:v', 'libx264',
        '-preset', 'medium',
        '-crf', '23',
        '-c:a', 'aac',
        '-b:a', '128k',
        '-r', VIDEO_FPS.toString(),
        '-t', TARGET_DURATION.toString(),
        '-movflags', '+faststart' // Web optimization
      ])

      .output(outputPath)

      .on('start', (cmd) => {
        console.log('FFmpeg command:', cmd);
      })
      .on('progress', (progress) => {
        console.log('Processing: ' + progress.percent + '% done');
      })
      .on('end', () => {
        console.log('Video composition completed');
        resolve();
      })
      .on('error', (err) => {
        console.error('FFmpeg error:', err);
        reject(err);
      })
      .run();
  });

  // Step 5: Read final video file
  const videoBuffer = fs.readFileSync(outputPath);

  // Step 6: Clean up temp files
  // fs.unlinkSync(outputPath); // Keep for debugging

  // Return binary data
  return {
    json: {
      status: 'success',
      outputPath: outputPath,
      fileSize: videoBuffer.length,
      duration: TARGET_DURATION
    },
    binary: {
      data: {
        data: videoBuffer.toString('base64'),
        mimeType: 'video/mp4',
        fileName: `final_${$('Save Approved Script').item.json.bookId}.mp4`
      }
    }
  };

} catch (error) {
  console.error('Video composition failed:', error);

  // Send error notification
  // ... (Telegram notification logic)

  throw new Error('Video composition failed: ' + error.message);
}

